   486	// ── File watcher ──────────────────────────────────────────────────────────────
   487	
   488	function watchFile(checkoutId: string, filePath: string): void {
   489	  if (!existsSync(filePath)) return;
   490	  stopWatcher(checkoutId);
   491	
   492	  const watcher = chokidar.watch(filePath, {
   493	    persistent: true,
   494	    ignoreInitial: true,
   495	    awaitWriteFinish: { stabilityThreshold: 2000, pollInterval: 300 },
   496	  });
   497	
   498	  watcher.on("change", () => {
   499	    const record = active.get(checkoutId);
   500	    if (!record) return;
   501	    log.debug(`File changed: ${filePath}`);
   502	    notify();
   503	  });
   504	
   505	  watcher.on("unlink", () => {
   506	    const record = active.get(checkoutId);
   507	    if (!record) return;
   508	    record.errorMessage = "Workspace file was deleted.";
   509	    updateStatus(checkoutId, "error");
   510	  });
   511	
   512	  watchers.set(checkoutId, watcher);
   513	}
   514	
   515	function stopWatcher(checkoutId: string): void {
   516	  const w = watchers.get(checkoutId);
   517	  if (w) {
   518	    w.close();
   519	    watchers.delete(checkoutId);
   520	  }
   521	}

