     1	/**
     2	 * Quick hash computation per PROJECT_BIBLE §9.
     3	 * Hash = SHA-256(first 64KB + last 64KB + file_size)
     4	 * This is NOT a full content hash — it's for move detection.
     5	 */
     6	
     7	import { createHash } from "node:crypto";
     8	import { open, stat } from "node:fs/promises";
     9	import { logger } from "./logger.js";
    10	
    11	const CHUNK_SIZE = 65536; // 64KB
    12	const HASH_VERSION = 1;
    13	
    14	export interface QuickHashResult {
    15	  quick_hash: string;
    16	  quick_hash_version: number;
    17	}
    18	
    19	export async function computeQuickHash(filePath: string): Promise<QuickHashResult> {
    20	  const fileStat = await stat(filePath);
    21	  const fileSize = fileStat.size;
    22	
    23	  const hash = createHash("sha256");
    24	
    25	  const fh = await open(filePath, "r");
    26	  try {
    27	    // Read first 64KB
    28	    const firstBuf = Buffer.alloc(Math.min(CHUNK_SIZE, fileSize));
    29	    await fh.read(firstBuf, 0, firstBuf.length, 0);
    30	    hash.update(firstBuf);
    31	
    32	    // Read last 64KB (if file > 64KB, otherwise already covered)
    33	    if (fileSize > CHUNK_SIZE) {
    34	      const lastBuf = Buffer.alloc(Math.min(CHUNK_SIZE, fileSize));
    35	      const offset = Math.max(0, fileSize - CHUNK_SIZE);
    36	      await fh.read(lastBuf, 0, lastBuf.length, offset);
    37	      hash.update(lastBuf);
    38	    }
    39	
    40	    // Include file size in hash for uniqueness
    41	    const sizeBuf = Buffer.alloc(8);
    42	    sizeBuf.writeBigUInt64LE(BigInt(fileSize));
    43	    hash.update(sizeBuf);
    44	  } finally {
    45	    await fh.close();
    46	  }
    47	
    48	  return {
    49	    quick_hash: hash.digest("hex"),
    50	    quick_hash_version: HASH_VERSION,
    51	  };
    52	}

