    75	export function corsServe(handler: (req: Request) => Promise<Response>): void {
    76	  serve(async (req: Request) => {
    77	    const origin = req.headers.get("Origin");
    78	    const allowedOrigin = resolveAllowedOrigin(origin);
    79	    const hdrs = buildCorsHeaders(allowedOrigin);
